import { describe, expect, it } from "vitest";

import { getPreviewPosition } from "./EyeDropper";

const PREVIEW_SIZE = 48; // 3rem at 16px base
const VIEWPORT_W = 1024;
const VIEWPORT_H = 768;

const pos = (cx: number, cy: number) =>
  getPreviewPosition(cx, cy, PREVIEW_SIZE, PREVIEW_SIZE, VIEWPORT_W, VIEWPORT_H);

describe("getPreviewPosition", () => {
  it("places the preview below-right of the pointer by default", () => {
    const { top, left } = pos(100, 100);
    expect(left).toBe(120); // 100 + 20
    expect(top).toBe(120);  // 100 + 20
  });

  it("flips left when the preview would overflow the right edge", () => {
    const { left } = pos(VIEWPORT_W - 10, 100);
    // should flip: clientX - 20 - previewWidth
    expect(left).toBe(VIEWPORT_W - 10 - 20 - PREVIEW_SIZE);
  });

  it("flips up when the preview would overflow the bottom edge", () => {
    const { top } = pos(100, VIEWPORT_H - 10);
    expect(top).toBe(VIEWPORT_H - 10 - 20 - PREVIEW_SIZE);
  });

  it("flips both axes in the bottom-right corner", () => {
    const { top, left } = pos(VIEWPORT_W - 5, VIEWPORT_H - 5);
    expect(left).toBe(VIEWPORT_W - 5 - 20 - PREVIEW_SIZE);
    expect(top).toBe(VIEWPORT_H - 5 - 20 - PREVIEW_SIZE);
  });

  it("does not flip when the preview just fits on the right", () => {
    // clientX + 20 + PREVIEW_SIZE === VIEWPORT_W  →  exactly fits
    const cx = VIEWPORT_W - 20 - PREVIEW_SIZE;
    const { left } = pos(cx, 100);
    expect(left).toBe(cx + 20);
  });

  it("does not flip when the preview just fits on the bottom", () => {
    const cy = VIEWPORT_H - 20 - PREVIEW_SIZE;
    const { top } = pos(100, cy);
    expect(top).toBe(cy + 20);
  });

