export const activeEyeDropperAtom = atom<null | EyeDropperProperties>(null);

/** Offset (px) between the pointer and the colour-preview box. */
const PREVIEW_OFFSET = 20;

/**
 * Compute the preview position so it stays fully inside the viewport.
 *
 * Default placement: below-right of the pointer (`+PREVIEW_OFFSET`).
 * If the preview would overflow the right edge it flips left;
 * if it would overflow the bottom edge it flips up.
 */
export const getPreviewPosition = (
  clientX: number,
  clientY: number,
  previewWidth: number,
  previewHeight: number,
  viewportWidth: number,
  viewportHeight: number,
): { top: number; left: number } => {
  let left = clientX + PREVIEW_OFFSET;
  let top = clientY + PREVIEW_OFFSET;

  if (left + previewWidth > viewportWidth) {
    left = clientX - PREVIEW_OFFSET - previewWidth;
  }

  if (top + previewHeight > viewportHeight) {
    top = clientY - PREVIEW_OFFSET - previewHeight;
  }

  return { top, left };
};

export const EyeDropper: React.FC<{
  onCancel: () => void;
  onSelect: EyeDropperProperties["onSelect"];
  /** called when color changes, on pointerdown for preview */
  onChange: (
    type: ColorPickerType,
    color: string,
    selectedElements: ExcalidrawElement[],
    event: { altKey: boolean },
  ) => void;

